"""Linux launcher bundle installer."""
from __future__ import annotations

from pathlib import Path

from _state_record import Manifest

from ._base_launcher import (
    DISPATCHER_WORKFLOWS,
    INVOKE_SKILL_WORKFLOWS,
    LauncherBundleSpec,
    LauncherFileSpec,
    LauncherInstallResult,
    LauncherInstallerBase,
)


def _unix_dispatcher_content(repo_root: Path) -> str:
    repo = LauncherInstallerBase._shell_quote_path(repo_root)
    return (
        "#!/bin/bash\n"
        "# Generated by install-assistant-tools - do not edit manually.\n"
        "# Runs officina.dispatcher directly from the repo ($AI): first-party code\n"
        "# is never pip-installed, so there is no second copy to drift or break.\n"
        f'AI="${{AI:-{repo}}}"\n'
        'export PYTHONPATH="$AI/src${PYTHONPATH:+:$PYTHONPATH}"\n'
        'exec python3 -m officina.dispatcher.cli "$@"\n'
    )


def _unix_invoke_skill_content() -> str:
    return (
        "#!/bin/bash\n"
        "# Generated by install-assistant-tools - do not edit manually.\n"
        "# Invokes a skill via the assistant command for recurring tasks.\n"
        "# Uses $CLAUDE_HOME to find the recurring-tasks skill at runtime.\n"
        "set -euo pipefail\n"
        "\n"
        "if [[ $# -ne 1 ]]; then\n"
        "  echo 'Usage: invoke-skill <skill-name>' >&2\n"
        "  exit 2\n"
        "fi\n"
        "\n"
        "skill=\"$1\"\n"
        "claude_home=\"${CLAUDE_HOME:-$HOME/.claude}\"\n"
        "recurring_tasks_dir=\"$claude_home/skills/recurring-tasks\"\n"
        "invoke_agent=\"$recurring_tasks_dir/_rtx/_agent_invoker.sh\"\n"
        "\n"
        "if [[ ! -x \"$invoke_agent\" ]]; then\n"
        "  echo \"ERROR: invoke-agent.sh not found at: $invoke_agent\" >&2\n"
        "  exit 1\n"
        "fi\n"
        "\n"
        "exec \"$invoke_agent\" \"$skill\"\n"
    )


class LinuxLauncherInstaller(LauncherInstallerBase):
    """Install launcher bundles on Linux-like hosts."""

    static_launcher_mode = "link"

    def install_dispatcher_launcher(
        self,
        repo_root: Path,
        bin_dir: Path,
        dry_run: bool,
        manifest: Manifest | None = None,
    ) -> LauncherInstallResult:
        bundle = LauncherBundleSpec(
            name="dispatcher",
            workflows=DISPATCHER_WORKFLOWS,
            files=[
                LauncherFileSpec(
                    destination=bin_dir / "dispatcher",
                    mode="generate",
                    content=_unix_dispatcher_content(repo_root),
                    executable=True,
                )
            ],
        )
        return self.install_bundle(bundle, dry_run=dry_run, manifest=manifest)

    def install_invoke_skill_launcher(
        self,
        bin_dir: Path,
        dry_run: bool,
        manifest: Manifest | None = None,
    ) -> LauncherInstallResult:
        bundle = LauncherBundleSpec(
            name="invoke-skill",
            workflows=INVOKE_SKILL_WORKFLOWS,
            files=[
                LauncherFileSpec(
                    destination=bin_dir / "invoke-skill",
                    mode="generate",
                    content=_unix_invoke_skill_content(),
                    executable=True,
                )
            ],
        )
        return self.install_bundle(bundle, dry_run=dry_run, manifest=manifest)

    def install_agent_launcher_files(
        self,
        *,
        source_bin_dir: Path,
        bin_dir: Path,
        agent: str,
        dry_run: bool,
        manifest: Manifest | None,
    ) -> None:
        if agent == "tw":
            bundle = LauncherBundleSpec(
                name="tw",
                required=False,
                workflows=("tmux workspace launcher",),
                files=[
                    LauncherFileSpec(
                        source=source_bin_dir / "tmux-workspace",
                        destination=bin_dir / "tmux-workspace",
                        mode=self.static_launcher_mode,
                    ),
                    LauncherFileSpec(
                        source=source_bin_dir / "tmux-workspace",
                        destination=bin_dir / "tw",
                        mode=self.static_launcher_mode,
                    ),
                ],
            )
        else:
            bundle = LauncherBundleSpec(
                name=agent,
                required=False,
                workflows=("agent launcher",),
                files=self._agent_launcher_files(source_bin_dir, bin_dir, agent),
            )
        self.install_bundle(bundle, dry_run=dry_run, manifest=manifest)
